// Uses the $variables: $Taint, $LastTaint, $PostTaintLink
window.taintLink = function (link) {
	var	sv      = State.variables;
	var newTier = Math.floor(sv.Taint / 5);
	var oldTier = Math.floor(sv.LastTaint / 5);

	// if the player has entered a new tier, set the
	// $PostTaintLink variable to the original link and
	// send them to the "Taint Events" passage instead
	if (newTier > oldTier) {
		sv.PostTaintLink = link;
		return "Taint Events";
	}

	// no new taint tier, so return the original link
	return link;
};

